SELECT
FROM tb_pmb_plan_benefits a LEFT OUTER JOIN (
SELECT plan_benefits_id, count(*) planCount FROM tb_pmb_plan_benefits_list A JOIN tb_pmb_plan_list B ON A.plan_list_id = B.id LEFT OUTER JOIN tb_mbm_company_list as C ON B.host = C.id GROUP BY A.plan_benefits_id
) as b ON a.id = b.plan_benefits_id
ORDER BY display_yn desc, create_date desc LIMIT #{offset}, #{recordSize}

SELECT
FROM tb_pmb_plan_benefits_list a, tb_pmb_plan_list b, tb_pmb_plan_benefits c WHERE a.plan_list_id = b.id AND a.plan_benefits_id = c.id
ORDER BY a.order_no, a.create_date LIMIT #{offset}, #{recordSize}

